import asyncio
import json
import secrets
import time
from dataclasses import dataclass, field
from typing import Dict, Optional, Set, Tuple, Any, List

import websockets
from websockets.server import WebSocketServerProtocol


def now_ms() -> int:
    return int(time.time() * 1000)


def jdump(obj: Any) -> str:
    return json.dumps(obj, separators=(",", ":"), ensure_ascii=False)


def jload(s: str) -> Any:
    return json.loads(s)


@dataclass
class Item:
    item_id: str
    template: str
    owner_id: str
    qty: int = 1
    meta: Dict[str, Any] = field(default_factory=dict)


@dataclass
class Player:
    player_id: str
    name: str
    ws: Optional[WebSocketServerProtocol] = None
    connected: bool = False
    inventory: Dict[str, int] = field(default_factory=dict)  # item_id -> qty
    gold: int = 0
    session_token: str = field(default_factory=lambda: secrets.token_urlsafe(24))
    last_seen_ms: int = field(default_factory=now_ms)


class GameState:
    def __init__(self):
        self.players: Dict[str, Player] = {}
        self.items: Dict[str, Item] = {}
        self.ws_to_player: Dict[WebSocketServerProtocol, str] = {}
        self.player_locks: Dict[str, asyncio.Lock] = {}
        self.item_locks: Dict[str, asyncio.Lock] = {}
        self.trade_locks: Dict[Tuple[str, str], asyncio.Lock] = {}
        self.global_lock = asyncio.Lock()

    def get_player_lock(self, player_id: str) -> asyncio.Lock:
        lock = self.player_locks.get(player_id)
        if lock is None:
            lock = asyncio.Lock()
            self.player_locks[player_id] = lock
        return lock

    def get_item_lock(self, item_id: str) -> asyncio.Lock:
        lock = self.item_locks.get(item_id)
        if lock is None:
            lock = asyncio.Lock()
            self.item_locks[item_id] = lock
        return lock

    def get_trade_lock(self, a: str, b: str) -> asyncio.Lock:
        key = (a, b) if a <= b else (b, a)
        lock = self.trade_locks.get(key)
        if lock is None:
            lock = asyncio.Lock()
            self.trade_locks[key] = lock
        return lock

    def ensure_player(self, player_id: str, name: Optional[str] = None) -> Player:
        p = self.players.get(player_id)
        if p is None:
            p = Player(player_id=player_id, name=name or player_id)
            self.players[player_id] = p
        else:
            if name:
                p.name = name
        return p

    def create_item(self, owner_id: str, template: str, qty: int = 1, meta: Optional[Dict[str, Any]] = None) -> Item:
        item_id = secrets.token_urlsafe(12)
        it = Item(item_id=item_id, template=template, owner_id=owner_id, qty=qty, meta=meta or {})
        self.items[item_id] = it
        owner = self.ensure_player(owner_id)
        owner.inventory[item_id] = owner.inventory.get(item_id, 0) + qty
        return it


STATE = GameState()


async def ws_send(ws: WebSocketServerProtocol, msg: Dict[str, Any]) -> None:
    try:
        await ws.send(jdump(msg))
    except Exception:
        pass


async def send_to_player(player_id: str, msg: Dict[str, Any]) -> None:
    p = STATE.players.get(player_id)
    if not p or not p.ws or not p.connected:
        return
    await ws_send(p.ws, msg)


def inv_snapshot(player: Player) -> Dict[str, Any]:
    items = []
    for item_id, qty in player.inventory.items():
        it = STATE.items.get(item_id)
        if not it:
            continue
        items.append({
            "item_id": it.item_id,
            "template": it.template,
            "qty": qty,
            "meta": it.meta,
        })
    return {"player_id": player.player_id, "gold": player.gold, "items": items}


async def broadcast_presence(player: Player, online: bool) -> None:
    msg = {"type": "presence", "player_id": player.player_id, "online": online, "ts": now_ms()}
    for p in list(STATE.players.values()):
        if p.connected and p.ws:
            await ws_send(p.ws, msg)


def normalize_qty(qty: Any) -> int:
    try:
        q = int(qty)
    except Exception:
        return 0
    return q


async def transfer_item_atomic(from_id: str, to_id: str, item_id: str, qty: int, request_id: str) -> Tuple[bool, str]:
    if qty <= 0:
        return False, "invalid_qty"
    if from_id == to_id:
        return False, "same_player"
    it = STATE.items.get(item_id)
    if not it:
        return False, "item_not_found"

    trade_lock = STATE.get_trade_lock(from_id, to_id)
    item_lock = STATE.get_item_lock(item_id)

    async with trade_lock:
        async with item_lock:
            it2 = STATE.items.get(item_id)
            if not it2:
                return False, "item_not_found"
            if it2.owner_id != from_id:
                return False, "not_owner"

            from_p = STATE.players.get(from_id)
            to_p = STATE.players.get(to_id)
            if not from_p or not to_p:
                return False, "player_not_found"

            from_lock = STATE.get_player_lock(from_id)
            to_lock = STATE.get_player_lock(to_id)
            first, second = (from_lock, to_lock) if from_id <= to_id else (to_lock, from_lock)

            async with first:
                async with second:
                    available = from_p.inventory.get(item_id, 0)
                    if available < qty:
                        return False, "insufficient_qty"

                    from_p.inventory[item_id] = available - qty
                    if from_p.inventory[item_id] <= 0:
                        from_p.inventory.pop(item_id, None)

                    if qty == it2.qty:
                        it2.owner_id = to_id
                        to_p.inventory[item_id] = to_p.inventory.get(item_id, 0) + qty
                    else:
                        it2.qty -= qty
                        to_p.inventory[item_id] = to_p.inventory.get(item_id, 0) + qty
                        new_item_id = secrets.token_urlsafe(12)
                        new_item = Item(
                            item_id=new_item_id,
                            template=it2.template,
                            owner_id=to_id,
                            qty=qty,
                            meta=dict(it2.meta),
                        )
                        STATE.items[new_item_id] = new_item
                        to_p.inventory.pop(item_id, None)
                        to_p.inventory[new_item_id] = to_p.inventory.get(new_item_id, 0) + qty

                    from_p.last_seen_ms = now_ms()
                    to_p.last_seen_ms = now_ms()

    await send_to_player(from_id, {"type": "inventory_update", "request_id": request_id, "inventory": inv_snapshot(STATE.players[from_id]), "ts": now_ms()})
    await send_to_player(to_id, {"type": "inventory_update", "request_id": request_id, "inventory": inv_snapshot(STATE.players[to_id]), "ts": now_ms()})
    return True, "ok"


async def handle_login(ws: WebSocketServerProtocol, msg: Dict[str, Any]) -> Dict[str, Any]:
    player_id = str(msg.get("player_id") or "").strip()
    name = str(msg.get("name") or player_id).strip()
    token = msg.get("token")

    if not player_id:
        return {"type": "error", "code": "missing_player_id"}

    async with STATE.global_lock:
        p = STATE.ensure_player(player_id, name=name)
        if token and token != p.session_token:
            return {"type": "error", "code": "invalid_token"}
        p.ws = ws
        p.connected = True
        p.last_seen_ms = now_ms()
        STATE.ws_to_player[ws] = player_id

        if not p.inventory and not any(it.owner_id == player_id for it in STATE.items.values()):
            p.gold = 100
            STATE.create_item(player_id, "starter_sword", qty=1, meta={"rarity": "common"})
            STATE.create_item(player_id, "health_potion", qty=5, meta={"rarity": "common"})

    await broadcast_presence(p, True)
    return {"type": "login_ok", "player_id": p.player_id, "name": p.name, "token": p.session_token, "inventory": inv_snapshot(p), "ts": now_ms()}


async def handle_inventory(ws: WebSocketServerProtocol, msg: Dict[str, Any]) -> Dict[str, Any]:
    pid = STATE.ws_to_player.get(ws)
    if not pid:
        return {"type": "error", "code": "not_logged_in"}
    p = STATE.players.get(pid)
    if not p:
        return {"type": "error", "code": "not_logged_in"}
    p.last_seen_ms = now_ms()
    return {"type": "inventory", "inventory": inv_snapshot(p), "ts": now_ms()}


async def handle_trade_request(ws: WebSocketServerProtocol, msg: Dict[str, Any]) -> Dict[str, Any]:
    from_id = STATE.ws_to_player.get(ws)
    if not from_id:
        return {"type": "error", "code": "not_logged_in"}

    to_id = str(msg.get("to_player_id") or "").strip()
    item_id = str(msg.get("item_id") or "").strip()
    qty = normalize_qty(msg.get("qty"))
    request_id = str(msg.get("request_id") or secrets.token_urlsafe(10))

    if not to_id or not item_id:
        return {"type": "trade_result", "request_id": request_id, "ok": False, "code": "missing_fields", "ts": now_ms()}

    ok, code = await transfer_item_atomic(from_id, to_id, item_id, qty, request_id)
    return {"type": "trade_result", "request_id": request_id, "ok": ok, "code": code, "ts": now_ms()}


async def handle_spawn_item(ws: WebSocketServerProtocol, msg: Dict[str, Any]) -> Dict[str, Any]:
    pid = STATE.ws_to_player.get(ws)
    if not pid:
        return {"type": "error", "code": "not_logged_in"}
    template = str(msg.get("template") or "").strip()
    qty = normalize_qty(msg.get("qty"))
    if not template or qty <= 0:
        return {"type": "error", "code": "invalid_fields"}
    meta = msg.get("meta")
    if meta is not None and not isinstance(meta, dict):
        meta = {}
    async with STATE.get_player_lock(pid):
        it = STATE.create_item(pid, template, qty=qty, meta=meta or {})
        STATE.players[pid].last_seen_ms = now_ms()
    return {"type": "spawn_ok", "item": {"item_id": it.item_id, "template": it.template, "qty": it.qty, "meta": it.meta}, "inventory": inv_snapshot(STATE.players[pid]), "ts": now_ms()}


async def handle_who(ws: WebSocketServerProtocol, msg: Dict[str, Any]) -> Dict[str, Any]:
    online = []
    for p in STATE.players.values():
        if p.connected:
            online.append({"player_id": p.player_id, "name": p.name})
    return {"type": "who", "online": online, "ts": now_ms()}


async def route(ws: WebSocketServerProtocol, msg: Dict[str, Any]) -> Dict[str, Any]:
    t = msg.get("type")
    if t == "login":
        return await handle_login(ws, msg)
    if t == "inventory":
        return await handle_inventory(ws, msg)
    if t == "trade":
        return await handle_trade_request(ws, msg)
    if t == "spawn_item":
        return await handle_spawn_item(ws, msg)
    if t == "who":
        return await handle_who(ws, msg)
    return {"type": "error", "code": "unknown_type", "ts": now_ms()}


async def client_loop(ws: WebSocketServerProtocol) -> None:
    try:
        async for raw in ws:
            try:
                msg = jload(raw)
                if not isinstance(msg, dict):
                    await ws_send(ws, {"type": "error", "code": "invalid_message"})
                    continue
            except Exception:
                await ws_send(ws, {"type": "error", "code": "invalid_json"})
                continue

            resp = await route(ws, msg)
            if resp is not None:
                await ws_send(ws, resp)
    finally:
        pid = STATE.ws_to_player.pop(ws, None)
        if pid:
            async with STATE.global_lock:
                p = STATE.players.get(pid)
                if p and p.ws is ws:
                    p.connected = False
                    p.ws = None
                    p.last_seen_ms = now_ms()
            if pid in STATE.players:
                await broadcast_presence(STATE.players[pid], False)


async def main(host: str = "0.0.0.0", port: int = 8765) -> None:
    async with websockets.serve(client_loop, host, port, ping_interval=20, ping_timeout=20, max_size=2**20):
        await asyncio.Future()


